import{_ as e,o as t,c as r,a2 as s}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"플랫폼 관리 운영 완성 (004 잔여 마감)","description":"","frontmatter":{"title":"플랫폼 관리 운영 완성 (004 잔여 마감)","feature_id":"005","status":"draft","created":"2026-05-31 15:50 (KST)","date":"2026-05-31T00:00:00.000Z","tags":["agent","platform","audit","security","mail","observability"]},"headers":[],"relativePath":"specs/005-platform-ops-completion/spec.md","filePath":"specs/005-platform-ops-completion/spec.md","lastUpdated":null}'),a={name:"specs/005-platform-ops-completion/spec.md"};function n(i,o,l,d,c,g){return t(),r("div",null,[...o[0]||(o[0]=[s('<h1 id="spec-플랫폼-관리-운영-완성-feature-004-잔여-항목-마감" tabindex="-1">Spec: 플랫폼 관리 운영 완성 (feature 004 잔여 항목 마감) <a class="header-anchor" href="#spec-플랫폼-관리-운영-완성-feature-004-잔여-항목-마감" aria-label="Permalink to &quot;Spec: 플랫폼 관리 운영 완성 (feature 004 잔여 항목 마감)&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>feature 004(플랫폼 관리 기능 이관)는 22개 관리 기능의 백엔드를 완성했지만, <strong>운영 투입에 필요한 일부 관측성·접근통제·외부연동을 의도적으로 후속으로 미뤘다</strong>. 그 격차가 지금 남아 있다:</p><ul><li><strong>SQL 실행 이력이 비어 있다</strong> — <code>AUDIT_SQL_LOG</code> 조회 경로는 있으나 기록하는 곳이 없어, &quot;누가 어떤 DB 작업을 했는가&quot;의 절반(SQL 레벨)이 관측 불가다(004 T018 부분).</li><li><strong>메뉴 권한이 인증 수준에 머문다</strong> — 역할↔메뉴 권한(<code>SYS_ROLE_MENU</code>)이 메뉴 노출 필터링에는 쓰이지만, 실제 기능 호출을 그 권한으로 <strong>차단하지는 않는다</strong>(004 T016 부분).</li><li><strong>메일을 실제로 보내지 못한다</strong> — 발송은 시도·결과를 기록만 하고 실 SMTP 전송이 없다 (004 plan 범위 밖).</li><li><strong>API 탐색 문서가 없다</strong> — springdoc 이 Boot4 호환 보류로 빠져 있어, 외부 소비자가 엔드포인트를 탐색·시험 호출할 수단이 없다(004 plan 범위 밖).</li></ul><p>운영 환경에 올리기 전에 이 네 가지 격차를 닫아 <strong>관측성(감사)·접근통제·실연동·문서화</strong>를 완성한다. 새 업무 기능은 추가하지 않는다 — 004 가 만든 기반의 <strong>마감</strong>이다.</p><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><blockquote><p><strong>구현 순서(2026-05-31 결정)</strong>: 프론트엔드 착수를 위한 <strong>enabler(① CORS, ② OpenAPI)를 먼저</strong> 마감하고, 나머지 백엔드 잔여(③ SQL 이력 · ④ 메뉴 세분 권한 · ⑤ 실 SMTP)는 프론트 작업과 병행/후속으로 진행한다. 프론트 스택은 <strong>Vue 3 + Vite, 별도 dev server + 프록시</strong>(별도 출처)이므로 CORS 가 실제 차단요인이다.</p></blockquote><h3 id="포함" tabindex="-1">포함 <a class="header-anchor" href="#포함" aria-label="Permalink to &quot;포함&quot;">​</a></h3><ol><li><strong>CORS 허용(프론트 enabler)</strong> — 프론트 개발 서버(별도 출처, 예: <code>localhost:5173</code>)가 <code>/api/v1/**</code> 를 호출할 수 있도록 CORS 를 설정한다. 허용 출처는 설정값으로 외부화하고, 운영(동일 출처 배포) 시에도 안전하게 동작한다.</li><li><strong>API 문서(OpenAPI) 도입(프론트 enabler)</strong> — Boot4 호환 springdoc 로 엔드포인트 탐색·시험 호출 UI 와 <code>/v3/api-docs</code> 를 제공(프론트 API 클라이언트 생성 지원). 호환 버전 미확인 시 보류로 표시하고 나머지 항목은 독립 진행.</li><li><strong>SQL 실행 이력 기록</strong> — 애플리케이션이 실행하는 SQL 을 가로채 <code>AUDIT_SQL_LOG</code> 에 기록(행위자·SQL·파라미터·소요시간·영향행수·시각). <code>/audit/sql-logs</code> 조회에 실데이터.</li><li><strong>메뉴 세분 권한 enforcement</strong> — 보호 API 호출 시, 호출자 역할의 <code>SYS_ROLE_MENU</code> 권한(<code>CAN_VIEW</code>/<code>CAN_EXEC</code>)을 평가해 권한 없는 메뉴 기능 호출을 거부(관리자 예외).</li><li><strong>실 SMTP 발송 연동</strong> — <code>SYS_SETTING</code> 의 SMTP 설정으로 실제 메일을 전송. 성공 시 <code>SENT</code>, 실패 시 <code>FAILED</code>+사유, 재발송 동작. 설정 부재 시 기존 &quot;기록만&quot; 모드로 안전 폴백.</li></ol><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li>새 업무 기능·새 엔터티 없음. 기존 22기능의 동작은 변경하지 않는다.</li><li>langgraph4j 그래프 토폴로지 무변경.</li><li>프런트엔드/데모 UI 변경 없음(VuGrid 데모는 그대로).</li><li>외부 메일 평판·대량발송·큐잉 인프라는 범위 밖(단건/소량 동기 전송).</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><table tabindex="0"><thead><tr><th>스토리</th><th>우선순위</th><th>내용</th></tr></thead><tbody><tr><td>US1</td><td>P1</td><td><strong>SQL 감사</strong> — 관리자가 기간·사용자로 SQL 실행 이력을 조회해 DB 작업을 추적한다.</td></tr><tr><td>US2</td><td>P1</td><td><strong>메뉴 세분 권한</strong> — 역할에 특정 메뉴 권한이 없는 사용자가 그 메뉴 기능 API 를 호출하면 거부된다.</td></tr><tr><td>US3</td><td>P2</td><td><strong>실 메일 발송</strong> — 관리자가 SMTP 설정 후 양식을 발송하면 실제 수신자에게 메일이 도달하고, 실패 시 사유가 남아 재발송할 수 있다.</td></tr><tr><td>US4</td><td>P3</td><td><strong>API 문서</strong> — 개발자가 문서 UI 에서 엔드포인트를 탐색하고 시험 호출한다.</td></tr></tbody></table><p>상세 흐름:</p><ol><li><strong>US1</strong> — 관리자가 사용자를 생성/수정하면 그 트랜잭션의 SQL 들이 <code>AUDIT_SQL_LOG</code> 에 남고, <code>GET /api/v1/audit/sql-logs?from=…&amp;to=…&amp;actor=…</code> 로 조회된다.</li><li><strong>US2</strong> — 일반 사용자(역할에 <code>/api/v1/codes</code> 메뉴 권한 없음)가 코드 생성 API 를 호출하면 <code>403</code>. 같은 메뉴에 <code>CAN_EXEC=Y</code> 인 역할 보유자는 통과. 관리자는 항상 통과.</li><li><strong>US3</strong> — 관리자가 <code>SYS_SETTING</code> 에 SMTP 호스트/포트/발신자 등을 설정한 뒤 <code>POST /api/v1/mails/send</code> → 수신자에게 실제 전송, <code>SENT</code> 기록. 전송 실패 시 <code>FAILED</code> +사유, <code>POST /logs/{id}/resend</code> 로 재시도.</li><li><strong>US4</strong> — 개발자가 <code>/swagger-ui</code> (또는 동등 경로)에서 22기능 엔드포인트를 본다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="기능-functional" tabindex="-1">기능 (Functional) <a class="header-anchor" href="#기능-functional" aria-label="Permalink to &quot;기능 (Functional)&quot;">​</a></h3><ul><li><strong>FR-0a (CORS)</strong>: 시스템은 설정된 허용 출처(프론트 dev server 등)에서 오는 <code>/api/v1/**</code> 요청에 대해 CORS 를 허용한다(자격증명/표준 헤더 포함). 허용 출처는 설정으로 외부화한다.</li><li><strong>FR-0b (OpenAPI)</strong>: 시스템은 OpenAPI 문서(<code>/v3/api-docs</code>)와 탐색 UI(<code>/swagger-ui</code>)를 제공한다. ✅ <strong>확인됨</strong> — springdoc-openapi 2.8.6 이 Spring Boot 4 에서 컨텍스트 적재 + 스펙 서빙 모두 동작(004 의 보류 사유 해소). 문서/UI 경로는 미인증 공개.</li><li><strong>FR-1 (SQL 이력)</strong>: 시스템은 데이터 접근 계층에서 실행되는 SQL 을 가로채 행위자·SQL 텍스트·파라미터(절단)·소요시간(ms)·영향/조회 행수·시각을 <code>AUDIT_SQL_LOG</code> 에 기록한다. 기록 실패가 업무 트랜잭션을 깨뜨려서는 안 된다(best-effort).</li><li><strong>FR-2 (SQL 조회)</strong>: 기존 <code>GET /api/v1/audit/sql-logs</code> 가 실제 데이터를 기간/행위자/ 키워드로 페이징 조회한다(004 US4 조회 경로 재사용, 1년 보존 경계 동일 적용).</li><li><strong>FR-3 (메뉴 권한 평가)</strong>: 보호 API(<code>/api/v1/**</code>) 호출 시 호출자 역할의 <code>SYS_ROLE_MENU</code> 권한을 평가해, 대상 메뉴 기능에 대한 권한이 없으면 <code>403</code> 으로 거부한다. 읽기는 <code>CAN_VIEW</code>, 상태변경은 <code>CAN_EXEC</code> 기준. <code>ROLE_ADMIN</code> 은 평가를 우회한다.</li><li><strong>FR-4 (권한 매핑 일관성)</strong>: 요청 경로 ↔ 메뉴 매핑은 단일 출처로 관리되며, 매핑이 없는 경로는 기존 인증 통제(로그인 필요)로 폴백한다(통제 공백 0).</li><li><strong>FR-5 (실 SMTP)</strong>: <code>SYS_SETTING</code> 에 SMTP 설정이 있으면 실제 전송하고 결과(<code>SENT</code>/ <code>FAILED</code>+사유)를 <code>SYS_MAIL_LOG</code> 에 기록한다. 설정이 없으면 기존 기록-전용 모드로 폴백한다(앱 기동·기존 테스트에 영향 없음).</li><li><strong>FR-6 (재발송)</strong>: 실패 발송은 재발송 시 실제 재전송을 시도하고 <code>RETRY_COUNT</code> 를 올린다.</li><li><strong>FR-7 (API 문서)</strong>: Boot4 호환 OpenAPI 문서/UI 를 제공한다. 호환 버전 확정 불가 시 본 요구는 보류로 표시하고 나머지(FR-1~6)는 독립적으로 완료한다.</li></ul><h3 id="비기능-non-functional" tabindex="-1">비기능 (Non-functional) <a class="header-anchor" href="#비기능-non-functional" aria-label="Permalink to &quot;비기능 (Non-functional)&quot;">​</a></h3><ul><li><strong>FR-8 (성능)</strong>: SQL 이력 기록 활성화로 인한 일반 요청 응답 지연 증가는 체감 가능 수준 이하여야 한다(목표: 평균 10% 이내).</li><li><strong>FR-9 (안전 폴백)</strong>: 본 기능의 어떤 부분도 미설정/미가용 시 004 의 기존 동작을 깨뜨리지 않는다(SMTP 미설정·문서 미도입 시 기존 테스트 전부 통과 유지).</li><li><strong>FR-10 (보안)</strong>: SMTP 자격증명 등 비밀은 평문 노출을 피한다(환경변수/비밀 분리).</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><p>신규 엔터티 없음. 기존 004 스키마 재사용:</p><ul><li><strong>AUDIT_SQL_LOG</strong> (기존): <code>ACTOR_ID</code>, <code>SQL_TEXT</code>, <code>PARAMS</code>, <code>ROW_COUNT</code>, <code>ELAPSED_MS</code>, <code>OCCURRED_AT</code> — 본 기능이 비로소 <strong>기록</strong>한다.</li><li><strong>SYS_ROLE_MENU</strong> (기존): <code>CAN_VIEW</code>/<code>CAN_EXEC</code> — 본 기능이 <strong>enforcement</strong> 에 사용한다.</li><li><strong>SYS_SETTING</strong> (기존): SMTP 호스트/포트/발신자/사용 여부 등 설정 키.</li><li><strong>SYS_MAIL_LOG</strong> (기존): 실 전송 결과 반영.</li></ul><h2 id="contracts-api-그래프-인터페이스" tabindex="-1">Contracts (API / 그래프 인터페이스) <a class="header-anchor" href="#contracts-api-그래프-인터페이스" aria-label="Permalink to &quot;Contracts (API / 그래프 인터페이스)&quot;">​</a></h2><p>신규 엔드포인트 없음(동작 보강). 영향 표면:</p><ul><li><code>GET /api/v1/audit/sql-logs</code> — 빈 결과 → 실데이터.</li><li><code>/api/v1/**</code> 보호 엔드포인트 — 인증 통제 → 인증 + 메뉴 세분 권한 통제.</li><li><code>POST /api/v1/mails/send</code>, <code>POST /api/v1/mails/logs/{id}/resend</code> — 기록 → 실 전송.</li><li>(선택) <code>GET /swagger-ui</code>, <code>GET /v3/api-docs</code> — 신규 문서 표면.</li></ul><h2 id="assumptions-정보-기반-결정-—-clarify-plan-에서-확정" tabindex="-1">Assumptions (정보 기반 결정 — clarify/plan 에서 확정) <a class="header-anchor" href="#assumptions-정보-기반-결정-—-clarify-plan-에서-확정" aria-label="Permalink to &quot;Assumptions (정보 기반 결정 — clarify/plan 에서 확정)&quot;">​</a></h2><ul><li><strong>SQL 캡처 수단</strong>: 004 의존성에 이미 있는 <code>datasource-proxy</code> 로 DataSource 를 감싸 모든 SQL 실행을 가로챈다. 기록은 비동기/best-effort 로 성능 영향을 최소화한다.</li><li><strong>SQL 로깅 범위</strong>: 모든 SQL(조회 포함)을 기록하되, 파라미터·SQL 텍스트는 길이 절단. 과도한 볼륨은 004 의 1년 보존 정리 잡으로 관리.</li><li><strong>경로↔메뉴 매핑</strong>: <code>SYS_MENU.PATH</code> 와 API 베이스 경로의 대응(예: 메뉴 <code>/admin/users</code> ↔ <code>/api/v1/users</code>)을 단일 매핑 규칙으로 둔다. 매핑 없는 경로는 인증 통제로 폴백.</li><li><strong>읽기/실행 구분</strong>: <code>GET</code> → <code>CAN_VIEW</code>, 그 외(<code>POST/PUT/DELETE</code>) → <code>CAN_EXEC</code>.</li><li><strong>SMTP 설정 위치</strong>: <code>SYS_SETTING</code>(호스트/포트/발신자/TLS/사용여부), <strong>비밀번호는 환경변수</strong>로 주입(평문 DB 저장 회피).</li><li><strong>springdoc</strong>: ✅ 2.8.6 으로 Boot4 동작 확인 완료(가정 해소) — 도입함.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 관리자가 임의 관리 작업 후 <code>/audit/sql-logs</code> 에서 그 작업의 SQL 실행을 기간·행위자로 조회할 수 있다(해당 작업 SQL 이력 누락 0건).</li><li><strong>SC-2</strong>: 역할에 메뉴 권한이 없는 사용자의 해당 메뉴 기능 호출은 100% <code>403</code>, 권한 보유자·관리자는 100% 통과(우회 0건).</li><li><strong>SC-3</strong>: SMTP 설정 후 발송한 메일이 실제 수신함에 도달하며, 강제 실패 시 <code>FAILED</code> +사유가 남고 재발송으로 복구된다.</li><li><strong>SC-4</strong>: SQL 이력 활성화 시 대표 요청의 평균 응답 시간 증가가 10% 이내.</li><li><strong>SC-5</strong>: SMTP 미설정·문서 미도입 등 어떤 부분 미구성 상태에서도 004 의 기존 자동 테스트가 전부 통과(회귀 0).</li><li><strong>SC-6 (선택)</strong>: 개발자가 문서 UI 에서 전체 엔드포인트를 탐색·시험 호출할 수 있다.</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>[ ] SQL 이력 범위: <strong>모든 SQL</strong> 기록 vs <strong>변경 SQL(INSERT/UPDATE/DELETE)만</strong> — 관측 완전성 ↔ 볼륨/성능 트레이드오프(기본안: 모든 SQL + 절단 + 1년 보존).</li><li>[ ] 경로↔메뉴 매핑 방식: <strong>PATH 규칙 자동 매핑</strong> vs <strong>메뉴별 명시 매핑 테이블</strong> — 유지보수성 ↔ 정확성(기본안: 규칙 매핑 + 미매핑 폴백).</li><li>[x] <s>springdoc 포함 여부</s> — 해소: 2.8.6 Boot4 동작 확인, enabler 로 도입 완료.</li></ul>',32)])])}const p=e(a,[["render",n]]);export{u as __pageData,p as default};
